mapper.select:
select * from ( select orderid, jobid, actid, custid, DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, exclude_reason, DATE_FORMAT(actrole_end_date,'%Y/%m/%d') as actrole_end_date, DATE_FORMAT(archive_date,'%Y/%m/%d') as archive_date, DATE_FORMAT(delete_date,'%Y/%m/%d') as delete_date, DATE_FORMAT(restore_date,'%Y/%m/%d') as restore_date, DATE_FORMAT(arc_del_date,'%Y/%m/%d') as arc_del_date , DATE_FORMAT(last_base_date,'%Y/%m/%d') as last_base_date, DATE_FORMAT(expected_arc_del_date,'%Y/%m/%d') as expected_arc_del_date , cust_nm, birth_dt, address, rsdnt_altrntv_id, cust_pin, inst_cd, DATE_FORMAT(regdate,'%Y/%m/%d') as regdate, DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid, val1, val2, val3, val4, val5, val6, val7 from cotdl.tbl_piiextract
limit #{offset}, #{amount}
) a order by orderid desc , actid, custid, jobid

select count(1)
from cotdl.tbl_piiextract
where 1=1

	
		and cust_pin = #{ssn, jdbcType=VARCHAR}
	
	
		and custid = #{ssn, jdbcType=VARCHAR}
	
	
		and val1 = #{ssn, jdbcType=VARCHAR}
	
	
		and val2 = #{ssn, jdbcType=VARCHAR}
	

  and SUBSTRING( jobid, 1, 11 ) = 'PII_POLICY3'
  and ARCHIVE_DATE is not null and RESTORE_DATE is null and ARC_DEL_DATE is null

select orderid, jobid, actid, custid,  DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, exclude_reason,  DATE_FORMAT(actrole_end_date,'%Y/%m/%d') as actrole_end_date,  DATE_FORMAT(archive_date,'%Y/%m/%d') as archive_date,  DATE_FORMAT(delete_date,'%Y/%m/%d') as delete_date,  DATE_FORMAT(restore_date,'%Y/%m/%d') as restore_date,  DATE_FORMAT(arc_del_date,'%Y/%m/%d') as arc_del_date
	 ,  DATE_FORMAT(last_base_date,'%Y/%m/%d') as last_base_date,  DATE_FORMAT(expected_arc_del_date,'%Y/%m/%d') as expected_arc_del_date
	 , cust_nm, birth_dt, address, rsdnt_altrntv_id, cust_pin, inst_cd,  DATE_FORMAT(regdate,'%Y/%m/%d') as regdate,  DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid, val1, val2, val3, val4, val5, val6, val7
from cotdl.tbl_piiextract
where 1=1

	
		and cust_pin = #{ssn, jdbcType=VARCHAR}
	
	
		and custid = #{ssn, jdbcType=VARCHAR}
	
	
		and val1 = #{ssn, jdbcType=VARCHAR}
	
	
		and val2 = #{ssn, jdbcType=VARCHAR}
	

  and SUBSTRING( jobid, 1, 11 ) = 'PII_POLICY3'
  and ARCHIVE_DATE is not null and RESTORE_DATE is null and ARC_DEL_DATE is null
limit 1

select orderid, jobid, actid, custid, DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, exclude_reason, DATE_FORMAT(actrole_end_date,'%Y/%m/%d') as actrole_end_date, DATE_FORMAT(archive_date,'%Y/%m/%d') as archive_date, DATE_FORMAT(delete_date,'%Y/%m/%d') as delete_date, DATE_FORMAT(restore_date,'%Y/%m/%d') as restore_date, DATE_FORMAT(arc_del_date,'%Y/%m/%d') as arc_del_date , DATE_FORMAT(last_base_date,'%Y/%m/%d') as last_base_date, DATE_FORMAT(expected_arc_del_date,'%Y/%m/%d') as expected_arc_del_date , cust_nm, birth_dt, address, rsdnt_altrntv_id, cust_pin, inst_cd, DATE_FORMAT(regdate,'%Y/%m/%d') as regdate, DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid, val1, val2, val3, val4, val5, val6, val7 from cotdl.tbl_piiextract where 1=1
and custid = #{custid}
and orderid = #{orderid}

mapper.insert:
		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(arc_del_date, '%Y/%m/%d'), 'ARC_DEL', 'ALL', COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = #{excludeReason}
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND arc_del_date IS NOT NULL 
		  
			
				 AND arc_del_date <= #{cutoffDate} 
			
			
				 AND restore_date <= #{cutoffDate} 
			
		  
		GROUP BY DATE_FORMAT(arc_del_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();

		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(archive_date, '%Y/%m/%d'), 'ARCHIVE', #{policyPrefix}, COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = #{excludeReason}
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND archive_date IS NOT NULL 
		  
			
				 AND arc_del_date <= #{cutoffDate} 
			
			
				 AND restore_date <= #{cutoffDate} 
			
		  
		GROUP BY DATE_FORMAT(archive_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();

		
		
		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(restore_date, '%Y/%m/%d'), 'RESTORE_ALL', 'ALL', COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = 'RESTORE'
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND restore_date IS NOT NULL 
		   AND restore_date <= #{cutoffDate} 
		GROUP BY DATE_FORMAT(restore_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();

		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(restore_date, '%Y/%m/%d'), 'RESTORE', #{policyPrefix}, COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = 'RESTORE'
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND restore_date IS NOT NULL 
		   AND restore_date <= #{cutoffDate} 
		GROUP BY DATE_FORMAT(restore_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();
		

		
		
		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(arc_del_date, '%Y/%m/%d'), 'ARC_DEL_DELARC', 'ALL', COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = 'DELARC'
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND arc_del_date IS NOT NULL 
		   AND arc_del_date <= #{cutoffDate} 
		GROUP BY DATE_FORMAT(arc_del_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();

		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(arc_del_date, '%Y/%m/%d'), 'ARC_DEL_DELARC_P', #{policyPrefix}, COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = 'DELARC'
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		   AND arc_del_date IS NOT NULL 
		   AND arc_del_date <= #{cutoffDate} 
		GROUP BY DATE_FORMAT(arc_del_date, '%Y/%m/%d')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW();
		

		
		INSERT INTO cotdl.TBL_PIIEXTRACT_PURGE_STAT (STAT_DATE, STAT_TYPE, JOBID_PREFIX, CNT, PURGE_DATE)
		SELECT DATE_FORMAT(basedate, '%Y%m'), 'BASEDATE', 'ALL', COUNT(*), NOW()
		FROM cotdl.tbl_piiextract
		WHERE EXCLUDE_REASON = #{excludeReason}
		  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
		  AND RESTORE_DATE IS NULL
		  
			
				 AND arc_del_date <= #{cutoffDate} 
			
			
				 AND restore_date <= #{cutoffDate} 
			
		  
		GROUP BY DATE_FORMAT(basedate, '%Y%m')
		ON DUPLICATE KEY UPDATE CNT = CNT + VALUES(CNT), PURGE_DATE = NOW()

INSERT IGNORE INTO cotdl.TBL_PIIEXTRACT_PURGE_LOG (CUSTID, JOBID, BASEDATE, ORDERID, ARC_DEL_DATE, RESTORE_DATE, EXCLUDE_REASON, PURGE_DATE)
SELECT CUSTID, JOBID, BASEDATE, ORDERID, ARC_DEL_DATE, RESTORE_DATE, EXCLUDE_REASON, NOW()
FROM cotdl.tbl_piiextract
WHERE EXCLUDE_REASON = #{excludeReason}
  AND SUBSTR(jobid, 1, 11) = #{policyPrefix}
  
	
		 AND arc_del_date <= #{cutoffDate} 
	
	
		 AND restore_date <= #{cutoffDate}

